def minimizeStringValue(self, s: str) -> str:
    count_table = {}
    for c in s:
        if c in count_table:
            count_table[c] += 1
        else:
            count_table[c] = 1

    result = ""
    for i in range(len(s)):
        if s[i] == '?':
            min_count = float('inf')
            for c in count_table:
                if count_table[c] < min_count:
                    min_count = count_table[c]
                    result += c

            s[i] = result
        else:
            s[i] = s[i]

    return s

